```cpp
#include <iostream>
#include <unistd.h>
#include <sys/wait.h>
#include <cstring>

int main() {
    int pipefd[2];
    if (pipe(pipefd) == -1) {
        std::cerr << "pipe failed" << std::endl;
        return 1;
    }

    pid_t pid = fork();
    if (pid == -1) {
        std::cerr << "fork failed" << std::endl;
        return 1;
    }

    if (pid == 0) { // Child process
        // Close unnecessary file descriptors
        close(pipefd[1]); // close write end in child

        dup2(pipefd[0], STDIN_FILENO); // redirect child's stdin to read end of pipe
        close(pipefd[0]); // close read end

        execlp("/bin/cat", "cat", NULL); // replace child process with cat
        std::cerr << "execlp failed" << std::endl;
        _exit(1);
    } else { // Parent process
        // Close unnecessary file descriptors
        close(pipefd[0]); // close read end in parent

        dup2(pipefd[1], STDOUT_FILENO); // redirect parent's stdout to write end of pipe
        close(pipefd[1]); // close write end

        std::string input = "Hello from the parent process!";
        write(STDOUT_FILENO, input.c_str(), input.size()); // write to the pipe

        wait(NULL); // wait for child to finish

        std::cout << "Parent process received: " << std::endl;
        char buffer[1024];
        read(pipefd[0], buffer, sizeof(buffer)); // read from the pipe
        std::cout << buffer << std::endl;
    }

    return 0;
}
```

This code demonstrates how to create a pipe, fork a child process, and connect the pipe’s file descriptors to the standard input and output of the child process. The parent process writes to the pipe, and the child process reads from the pipe using `/bin/cat`.

